var DEFAULT_SETTINGS = {
  sortBy: "name",
  sortOrder: "asc",
  hiddenExtensions: [],
  treeExtensions: [".md", ".canvas", ".excalidraw.md"],
  treeSortEnabled: true,
  theme: "default",
  lang: "zh-CN",
  treeSplit: 50
};
var VaultViewerSettingTab = class extends import_obsidian.PluginSettingTab {
  constructor(app, plugin) {
    super(app, plugin);
    this.plugin = plugin;
  }
  display() {
    const { containerEl } = this;
    containerEl.empty();
    new import_obsidian.Setting(containerEl).setName(t("settings.title")).setHeading();
    new import_obsidian.Setting(containerEl).setName(t("settings.theme")).setDesc(t("settings.themeDesc")).addDropdown(
      (dd) => dd.addOption("default", t("settings.themeDefault")).addOption("fresh", t("settings.themeFresh")).setValue(this.plugin.settings.theme).onChange(async (val) => {
        this.plugin.settings.theme = val;
        await this.plugin.saveSettings();
        setIconTheme(val);
        void this.plugin.activateView(true);
      })
    );
    new import_obsidian.Setting(containerEl).setName(t("settings.lang")).setDesc(t("settings.langDesc")).addDropdown(
      (dd) => dd.addOption("zh-CN", "\u7B80\u4F53\u4E2D\u6587").addOption("zh-TW", "\u7E41\u9AD4\u4E2D\u6587").addOption("en", "English").setValue(this.plugin.settings.lang).onChange(async (val) => {
        this.plugin.settings.lang = val;
        await this.plugin.saveSettings();
        setLang(val);
        this.display();
        void this.plugin.activateView(true);
      })
    );
    new import_obsidian.Setting(containerEl).setName(t("settings.defaultSort")).setHeading();
    new import_obsidian.Setting(containerEl).setName(t("settings.defaultSort")).setDesc(t("settings.defaultSortDesc")).addDropdown(
      (dd) => dd.addOption("name", t("sort.name")).addOption("mtime", t("sort.mtime")).addOption("ctime", t("sort.ctime")).addOption("size", t("sort.size")).setValue(this.plugin.settings.sortBy).onChange(async (val) => {
        this.plugin.settings.sortBy = val;
        await this.plugin.saveSettings();
      })
    );
    new import_obsidian.Setting(containerEl).setName(t("settings.sortOrder")).addDropdown(
      (dd) => dd.addOption("asc", t("sort.asc")).addOption("desc", t("sort.desc")).setValue(this.plugin.settings.sortOrder).onChange(async (val) => {
        this.plugin.settings.sortOrder = val;
        await this.plugin.saveSettings();
      })
    );
    new import_obsidian.Setting(containerEl).setName(t("settings.hideTypes")).setHeading();
    new import_obsidian.Setting(containerEl).setName(t("settings.hideTypes")).setDesc(t("settings.hideTypesDesc")).addTextArea(
      (ta) => ta.setPlaceholder(".exe\n.zip\n.dll").setValue(this.plugin.settings.hiddenExtensions.join("\n")).onChange(async (val) => {
        this.plugin.settings.hiddenExtensions = val.split("\n").map((s) => s.trim()).filter((s) => s.startsWith("."));
        await this.plugin.saveSettings();
      })
    );
    new import_obsidian.Setting(containerEl).setName(t("settings.treeExtensions")).setHeading();
    new import_obsidian.Setting(containerEl).setName(t("settings.treeExtensions")).setDesc(t("settings.treeExtensionsDesc")).addTextArea(
      (ta) => ta.setPlaceholder(".md\n.canvas\n.excalidraw.md").setValue(this.plugin.settings.treeExtensions.join("\n")).onChange(async (val) => {
        this.plugin.settings.treeExtensions = val.split("\n").map((s) => s.trim()).filter((s) => s.startsWith("."));
        await this.plugin.saveSettings();
      })
    );
    new import_obsidian.Setting(containerEl).setName(t("settings.sortFolders")).setDesc(t("settings.sortFoldersDesc")).addToggle(
      (t2) => t2.setValue(this.plugin.settings.treeSortEnabled).onChange(async (val) => {
        this.plugin.settings.treeSortEnabled = val;
        await this.plugin.saveSettings();
      })
    );
  }
};

