var import_obsidian4 = require("obsidian");

// src/ui/InputModal.ts
var import_obsidian2 = require("obsidian");
var InputModal = class extends import_obsidian2.Modal {
  constructor(app, titleText, placeholder, defaultValue, onSubmit) {
    super(app);
    this.titleText = titleText;
    this.placeholder = placeholder;
    this.defaultValue = defaultValue;
    this.onSubmit = onSubmit;
    this.result = "";
  }
  onOpen() {
    const { contentEl } = this;
    contentEl.addClass("vault-viewer-input-modal");
    contentEl.createEl("h3", { text: this.titleText });
    const inputContainer = contentEl.createDiv({ cls: "vault-viewer-input-wrapper" });
    const inputEl = inputContainer.createEl("input", {
      cls: "vault-viewer-input-full",
      attr: { type: "text", placeholder: this.placeholder }
    });
    inputEl.value = this.defaultValue;
    this.result = this.defaultValue;
    inputEl.addEventListener("input", () => {
      this.result = inputEl.value;
    });
    inputEl.addEventListener("keydown", (e) => {
      if (e.key === "Enter") void this.submit();
    });
    inputEl.select();
    window.setTimeout(() => inputEl.focus(), 50);
    const btnContainer = contentEl.createDiv({ cls: "vault-viewer-input-buttons" });
    const okBtn = btnContainer.createEl("button", {
      cls: "vault-viewer-input-btn mod-cta",
      text: "\u786E\u5B9A"
    });
    okBtn.addEventListener("click", () => void this.submit());
    const cancelBtn = btnContainer.createEl("button", {
      cls: "vault-viewer-input-btn",
      text: "\u53D6\u6D88"
    });
    cancelBtn.addEventListener("click", () => this.close());
  }
  async submit() {
    if (this.result.trim()) {
      await this.onSubmit(this.result.trim());
      this.close();
    }
  }
  onClose() {
    this.contentEl.empty();
  }
};

// src/ui/ConfirmModal.ts
var import_obsidian3 = require("obsidian");
var ConfirmModal = class extends import_obsidian3.Modal {
  constructor(app, titleText, message, onConfirm) {
    super(app);
    this.titleText = titleText;
    this.message = message;
    this.onConfirm = onConfirm;
    this.resolved = false;
  }
  onOpen() {
    const { contentEl } = this;
    contentEl.addClass("vault-viewer-input-modal");
    contentEl.createEl("h3", { text: this.titleText });
    contentEl.createEl("p", { text: this.message });
    const btnContainer = contentEl.createDiv({ cls: "vault-viewer-input-buttons" });
    const okBtn = btnContainer.createEl("button", {
      cls: "vault-viewer-input-btn mod-cta",
      text: "\u786E\u8BA4\u5220\u9664"
    });
    okBtn.addEventListener("click", () => {
      void (async () => {
        this.resolved = true;
        await this.onConfirm();
        this.close();
      })();
    });
    const cancelBtn = btnContainer.createEl("button", {
      cls: "vault-viewer-input-btn",
      text: "\u53D6\u6D88"
    });
    cancelBtn.addEventListener("click", () => this.close());
  }
  onClose() {
    this.contentEl.empty();
  }
};

