          const cleanFont = {};
          Object.keys(font).forEach((key) => {
            if (font[key] !== null && font[key] !== void 0) {
              cleanFont[key] = font[key];
            }
          });
          return Object.keys(cleanFont).length > 0 ? cleanFont : null;
